// Features/Actions/Shared/Mappers/ActionDTOMapperDataContextService.cs

public class ActionDTOMapperDataContextService(
    IDbContextFactory<ActionsDbContext> dbContextFactory,
    ILogger<ActionDTOMapperDataContextService> logger)
{
    public async Task<ActionDTOMapperDataContext> GetAsync(
        Guid actionId,
        CancellationToken ct)
    {
        logger.LogDebug("Loading ActionDTOMapperDataContext for action {ActionId}",
            actionId);

        await using var dbContext = await dbContextFactory.CreateDbContextAsync(ct);

        // Start all queries in parallel
        var getEscalationRulesTask = dbContext.EscalationRules
            .AsNoTracking()
            .ToListAsync(ct);
        var getComplianceProfilesTask = dbContext.ComplianceProfiles
            .AsNoTracking()
            .ToListAsync(ct);

        await Task.WhenAll(getEscalationRulesTask, getComplianceProfilesTask);

        return new ActionDTOMapperDataContext
        {
            EscalationRuleMap = (await getEscalationRulesTask).ToDictionary(r => r.Id),
            ComplianceProfileMap = (await getComplianceProfilesTask).ToDictionary(p => p.Id)
        };
    }
}

// Features/Actions/Shared/Mappers/ActionDTOMapper.cs

public class ActionDTOMapper(TranslationService translationService)
{
    public ActionDTO Map(
        ActionEntity entity,
        Guid requestLanguageId,
        Guid defaultLanguageId,
        ActionDTOMapperDataContext context)
    {
        var translation = translationService.GetEntityTranslation(
            entity, requestLanguageId, defaultLanguageId);

        return new ActionDTO
        {
            Id = entity.Id,
            Name = translation.Name,
            Description = translation.Description,
            ReferenceNumber = entity.ReferenceNumber,
            Status = new EnumDTO((int)entity.Status, entity.Status.ToString()),
            Priority = new EnumDTO((int)entity.Priority, entity.Priority.ToString()),
            DueDate = entity.DueDate,
            CompletedDate = entity.CompletedDate,
            Version = entity.Version,
            CreatedDate = entity.CreatedDate,
            UpdatedDate = entity.UpdatedDate,

            // Navigation property — eager-loaded on entity
            WorkflowDefinition = new NamedDTO
            {
                Id = entity.WorkflowDefinition.Id,
                Name = entity.WorkflowDefinition.Code,
            },

            // From DTOMapperDataContext — additional data loaded in parallel
            Evidence = entity.Evidence
                .Select(e => new ActionEvidenceDTO
                {
                    Id = e.Id,
                    FileName = e.FileName,
                })
                .ToList(),
        };
    }

    public ActionGridItemDTO MapGridItem(
        ActionEntity entity,
        Guid requestLanguageId,
        Guid defaultLanguageId,
        ActionDTOMapperDataContext context)
    {
        var translation = translationService.GetEntityTranslation(
            entity, requestLanguageId, defaultLanguageId);

        return new ActionGridItemDTO
        {
            Id = entity.Id,
            Name = translation.Name,
            ReferenceNumber = entity.ReferenceNumber,
            StatusName = entity.Status.ToString(),
            PriorityName = entity.Priority.ToString(),
            WorkflowName = entity.WorkflowDefinition?.Code ?? string.Empty,
            DueDate = entity.DueDate,
            EvidenceCount = entity.Evidence.Count,
            CreatedDate = entity.CreatedDate,
        };
    }
}

// Features/Actions/Get/GetActionEndpoint.cs

public sealed class GetActionEndpoint(
    GetActionQuery getActionQuery,
    ActionDTOMapperDataContextService dataContextService,
    ActionDTOMapper dtoMapper)
    : TenantEndpointWithoutRequest<ActionDTO>
{
    public override void Configure()
    {
        Get("/api/v1/actions/{id}");
        Policies(ActionConstants.PolicyNames.ActionViewer);
    }

    protected override async Task HandleValidatedRequestAsync(CancellationToken ct)
    {
        var id = Route<Guid>("id");

        // 1. Load entity via query
        var action = await getActionQuery.ExecuteAsync(id, ct);
        if (action is null) { await Send.NotFoundAsync(ct); return; }

        // 2. Load additional context data (parallel queries)
        var context = await dataContextService.GetAsync(action.Id, ct);

        // 3. Map via DI-registered DTOMapper
        await Send.OkAsync(
            dtoMapper.Map(action, RequestLanguageId, DefaultLanguageId, context), ct);
    }
}

// Features/Actions/GetGridList/GetActionGridListEndpoint.cs

public sealed class GetActionGridListEndpoint(
    GetActionsQuery getActionsQuery,
    GetActionsCountQuery getActionsCountQuery,
    ActionDTOMapperDataContextService dataContextService,
    ActionDTOMapper dtoMapper)
    : TenantEndpoint<PagedRequest, GridListResponse<ActionGridItemDTO>>
{
    public override void Configure()
    {
        Post("/api/v1/actions/grid-list");
        Policies(ActionConstants.PolicyNames.ActionViewer);
    }

    protected override async Task HandleValidatedRequestAsync(
        PagedRequest req, CancellationToken ct)
    {
        var parameters = new ActionQueryParameters()
            .WithSearch(req.Search)
            .WithStatus(req.Status)
            .WithPagination(
                skip: (req.Page - 1) * req.PageSize,
                take: req.PageSize);

        var dataTask = getActionsQuery.ExecuteAsync(parameters, ct);
        var countTask = getActionsCountQuery.ExecuteAsync(parameters, ct);
        await Task.WhenAll(dataTask, countTask);

        // DTOMapperDataContext loaded once, used for all items
        var context = await dataContextService.GetAsync(ct);

        var items = (await dataTask)
            .Select(a => dtoMapper.MapGridItem(a, RequestLanguageId, DefaultLanguageId, context))
            .ToList();

        await Send.OkAsync(
            new GridListResponse<ActionGridItemDTO>(
                items, await countTask, req.Page, req.PageSize),
            ct);
    }
}

